#!/usr/bin/env python3
"""
MKT Original Commentary — 2 Kings chapters 1–3 (fill: prior script wrote only 2–3 key verses)
Run: python3 scripts/zc-original-2kings-fill-1-3.py

Ch 1: Ahaziah&#x2019;s inquiry of Baal-zebub; Elijah and the fire; death oracle fulfilled
Ch 2: Elijah&#x2019;s translation; Elisha&#x2019;s succession; Jordan miracle; Jericho water; bears
Ch 3: Joram&#x2019;s campaign against Moab; Mesha Stele connection; Elisha&#x2019;s prophetic music;
      Mesha&#x2019;s son sacrifice and the &#x201C;great wrath&#x201D;

Key Hebrew terms:
- saʿărah (2:1,11): whirlwind/storm — same root as Job 38:1 divine speech
- aderet Eliyahu (2:13-14): Elijah&#x2019;s mantle — symbol of prophetic succession
- noqed (3:4): sheep-farmer — same term used of Amos (Amos 1:1); Mesha Stele confirms
- qetsef gadol (3:27): great wrath — most discussed crux in Kings
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

TWO_KINGS = {
    "1": {
        "1": "<p><em>wayyipšaʿ Môʾāḇ bᵉYiśrāʾēl ʾaḥărê môṯ ʾAḥāḇ</em> — &#x201C;Moab rebelled against Israel after the death of Ahab.&#x221D; The verb <em>pāšaʿ</em> denotes a breach of vassal relationship — rebellion against treaty obligation. Moab had been a tributary of Israel since David&#x2019;s conquest (2 Sam 8:2); the Mesha Stele (the Moabite stone, c. 840 BCE) provides Mesha&#x2019;s own account of this rebellion: &#x201C;Omri had taken possession of Medeba... his son succeeded him and he also said, &#x2018;I will oppress Moab.&#x2019;... And I fought against it and took it.&#x221D; The biblical and Moabite accounts together give us the most fully documented event in the book of Kings.</p>",
        "3": "<p><em>ûmalʾaḵ YHWH dibber ʾel-ʾĒliyyāhû haTTišbî</em> — &#x201C;the messenger/angel of YHWH spoke to Elijah the Tishbite.&#x221D; The epithet <em>Tišbî</em> places Elijah&#x2019;s origin in Tishbe of Gilead (1 Kgs 17:1), across the Jordan — he is a prophet from the east who ministers primarily in Israel&#x2019;s northern kingdom. The oracle repeats verbatim the inquiry of Baal-zebub as a legal charge: sending to a foreign god implies YHWH has no word for Israel.</p>",
        "4": "<p><em>lāḵēn kōh-ʾāmar YHWH hammîṭṭāh ʾăšer-ʿālîṯā šām lōʾ-tēreḏ mimennāh kî môṯ tāmûṯ</em> — &#x201C;Therefore thus says YHWH: You shall not come down from the bed to which you have gone up, for you shall surely die.&#x221D; The death oracle uses the emphatic infinitive absolute <em>môṯ tāmûṯ</em> (&#x201C;dying you shall die&#x221D;) — the same construction as God&#x2019;s warning to Adam (Gen 2:17). The oracle is calibrated: the same bed Ahaziah retreated to in injury becomes the bed of his death. His failure to seek YHWH means YHWH&#x2019;s word is his only word — and it is a death sentence.</p>",
        "5": "<p>The messengers return to the king without completing their mission — an unusual reversal of the messenger convention. Ahaziah&#x2019;s question <em>maddûaʿ šaḇtem</em> — &#x201C;Why have you returned?&#x221D; — implies expectation of a longer absence. The narrative&#x2019;s interest is in how Elijah intercepted them: YHWH speaks through an anonymous prophet who appears without priestly credential or royal appointment.</p>",
        "6": "<p>The messengers relay the anonymous prophet&#x2019;s oracle word for word. The repetition in Hebrew narrative is deliberate — the threefold repetition of the oracle (vv. 3-4, 6, 16) creates an anaphoric structure that drives the narrative toward its inevitable fulfillment. <em>hayeš elohim bᵉYiśrāʾēl</em> — &#x201C;Is there no God in Israel?&#x221D; — is the central theological question the chapter answers.</p>",
        "7": "<p>Ahaziah&#x2019;s question about the prophet&#x2019;s appearance — <em>mah-mišpat hāʾîš</em> — asks for his characteristic feature, his identifying mark. The word <em>mišpāṭ</em> (normally &#x201C;judgment/right&#x221D;) here means &#x201C;manner/character.&#x221D; The identification by appearance rather than name reflects the anonymous nature of the prophetic encounter: Elijah was not sent by the royal court and did not identify himself.</p>",
        "9": "<p>Ahaziah sends a military captain with fifty men to arrest Elijah — a response that treats the prophet as a political criminal rather than a divine messenger. <em>ʾîš hāʾĕlōhîm</em> — &#x201C;man of God&#x221D; — is the honorific the captain uses, perhaps acknowledging Elijah&#x2019;s status even while summoning him. Elijah is sitting on top of a hill (<em>yōšēḇ ʿal-rōʾš hāhār</em>) — an elevated position that foreshadows what follows.</p>",
        "10": "<p><em>ʾim-ʾîš hāʾĕlōhîm ʾānî tēreḏ ʾēš min-haššāmayim wᵉtōḵal ʾōṯᵉḵā wᵉʾeṯ-ḥămiššêḵā</em> — &#x201C;If I am a man of God, let fire come down from heaven and consume you and your fifty.&#x221D; Elijah&#x2019;s conditional oracle is a test of his own status: if he is truly YHWH&#x2019;s man, YHWH will confirm it. The fire from heaven echoes Elijah&#x2019;s earlier fire-from-heaven at Carmel (1 Kgs 18:38). The <em>wayyēreḏ ʾēš</em> — fire coming down — is the fulfillment formula, identical in structure to the Carmel narrative.</p>",
        "11": "<p>The second captain&#x2019;s message is identical to the first&#x2019;s — even the phrasing &#x201C;man of God, thus says the king, come down quickly (<em>māhēr</em>)&#x221D; repeats verbatim. The king escalates without learning; the second company&#x2019;s death follows from the same dynamic. <em>māhēr</em> (quickly) adds urgency that heightens the contrast with the cosmic authority Elijah exercises.</p>",
        "12": "<p>The second oracle is structurally identical to the first, with the same result. The doubling establishes the pattern; the third captain&#x2019;s different approach (v. 13) will break it. The narrative&#x2019;s repetitive structure is a form of deliberate rhetoric — in oral tradition, the third encounter always differs, and here the difference saves the captain&#x2019;s life.</p>",
        "13": "<p>The third captain&#x2019;s posture — <em>wayyiḵraʿ ʿal-birkāyw nōkaḥ ʾĒliyyāhû wayyiṯḥannen ʾēlāyw</em> (&#x201C;he bent on his knees before Elijah and entreated him&#x221D;) — reverses the authoritarian approach of the first two. <em>ḥānan</em> (entreat/show favor) is the verb of mercy-seeking; his appeal &#x201C;let my life and the lives of your fifty servants be precious in your sight&#x221D; acknowledges Elijah&#x2019;s absolute authority over life and death.</p>",
        "14": "<p>The captain invokes what has already happened — fire consuming the first two captains with their fifties — as the ground for his appeal. His argument is not a denial of Elijah&#x2019;s authority but a submission to it. <em>wᵉʿattāh tîqar napšî bᵉʿênêḵā</em> — &#x201C;now let my life be precious in your eyes.&#x221D; The word <em>yāqār</em> (precious) is the same word used of rare things of great value; he asks that his life be treated as something worth preserving.</p>",
        "15": "<p><em>ûmalʾaḵ YHWH dibber ʾel-ʾĒliyyāhû</em> — the angel of YHWH instructs Elijah to go down without fear. The divine instruction releases Elijah from the posture of defensive authority into active ministry. The fire-oracle was YHWH&#x2019;s defense of Elijah&#x2019;s prophetic status; now the mission to deliver the oracle in person can proceed.</p>",
        "16": "<p>Elijah delivers the death oracle directly to Ahaziah. The personal delivery closes the narrative arc: the oracle has moved from angel to prophet to messengers and back; now it comes from the prophet&#x2019;s mouth to the king&#x2019;s ear. The repetition (<em>lāḵēn kōh-ʾāmar YHWH... môṯ tāmûṯ</em>) for the third time signals its irrevocability.</p>",
        "17": "<p><em>wayyāmāṯ kidbar YHWH ʾăšer dibber ʾĒliyyāhû</em> — &#x201C;he died according to the word of YHWH that Elijah spoke.&#x221D; The fulfillment formula <em>kidbar YHWH</em> appears at every major prophetic fulfillment in Kings (cf. 1 Kgs 17:16; 2 Kgs 9:26). Joram succeeds Ahaziah — but the narrative notes he had no son, completing the Ahaziah lineage. The transition is also synchronized with Jehoshaphat of Judah&#x2019;s second year.</p>",
        "18": "<p>The standard closing formula for Israelite kings refers to &#x201C;the book of the chronicles of the kings of Israel.&#x221D; Ahaziah&#x2019;s reign (two years) was entirely defined by his injury, his forbidden inquiry, and his death. The narrative has no other content for his reign — he is remembered only for what he sought from Baal-zebub and what he received from YHWH.</p>"
    },
    "2": {
        "1": "<p><em>wayhî bahăʿălôṯ YHWH ʾeṯ-ʾĒliyyāhû bassᵉʿārāh haššāmāyim</em> — &#x201C;when YHWH was about to take Elijah up to heaven in the storm-wind.&#x221D; <em>saʿărāh</em> (storm-wind, whirlwind) appears in Job 38:1 and 40:6 as the medium of divine speech; in Ezekiel 1:4 it introduces the divine chariot-throne vision. The same term describes the vehicle of Elijah&#x2019;s departure, placing his translation in the tradition of theophanic storm-presence. The journey begins at Gilgal — possibly the Gilgal near Bethel, associated with the early prophetic communities.</p>",
        "2": "<p>Elijah&#x2019;s threefold instruction &#x201C;Stay here&#x221D; (<em>šeḇ-nāʾ pōh</em>) and Elisha&#x2019;s threefold refusal — <em>ḥay-YHWH wᵉḥay-napšᵉḵā ʾim-ʾeʿezeḇekā</em> (&#x201C;as YHWH lives and as you yourself live, I will not leave you&#x221D;) — is the most direct echo of Ruth 1:16-17 in the prophetic books. Elisha&#x2019;s oath formula mirrors Ruth&#x2019;s covenant loyalty to Naomi. The narrative presents Elisha&#x2019;s persistence as a condition of his prophetic inheritance: he receives by not letting go.</p>",
        "3": "<p><em>wayyēṣᵉʾû ḇᵉnê-hannᵉḇîʾîm ʾăšer-bêṯ-ʾĒl ʾel-ʾĔlîšāʿ wayyōʾmᵉrû ʾēlāyw hayāḏaʿtā kî hayyôm YHWH lōqēaḥ ʾeṯ-ʾăḏōnêḵā mēʿal rōʾšêḵā</em> — &#x201C;Do you know that today YHWH is taking your master from over your head?&#x221D; The prophetic guild (<em>ḇᵉnê-hannᵉḇîʾîm</em> — sons of the prophets) at Bethel already knows. Elisha&#x2019;s response — &#x201C;Yes, I know; be silent&#x221D; — indicates that knowledge of the event does not diminish its weight. The command <em>hᵉḥāšû</em> (be silent) implies grief or reverence.</p>",
        "4": "<p>The second stage of the journey — to Jericho — repeats the Bethel pattern exactly. Elijah&#x2019;s instruction to stay and Elisha&#x2019;s oath of refusal are verbatim repetitions. The triadic structure (Gilgal → Bethel → Jericho → Jordan) traces a geographically significant path: the three holy sites of early Israelite history moving toward the Jordan, the liminal boundary of the land.</p>",
        "5": "<p>The sons of the prophets at Jericho repeat the question to Elisha. His answer is identical to v. 3 — the twice-said &#x201C;I know it; keep silent&#x221D; marks a growing weight of knowing. The prophetic community&#x2019;s awareness underscores that Elijah&#x2019;s translation is not a surprise but a disclosed divine act.</p>",
        "6": "<p>The third instruction to stay — this time at the Jordan — receives the same refusal. The YHWH-oath is unchanged: <em>ḥay-YHWH wᵉḥay-napšᵉḵā ʾim-ʾeʿezeḇekā</em>. The three-stage journey is complete; what remains is the crossing of the Jordan and whatever lies beyond it.</p>",
        "7": "<p>Fifty sons of the prophets stood watching from a distance (<em>meraḥōq</em>). The community witnesses but does not participate. Their standing at a distance mirrors the posture of worshipers before a theophany — present but separated. The fifty is a round number marking a substantial prophetic community at Jericho, consistent with the prophetic schools Elijah and Elisha led.</p>",
        "8": "<p><em>wayyiqqaḥ ʾĒliyyāhû ʾeṯ-ʾaddartô wayyiglōm wayyakkeh ʾeṯ-hammāyim wayyēḥāṣᵉʾû hēnnāh wᵉhēnnāh</em> — &#x201C;Elijah took his cloak (<em>adderet</em>), rolled it up, and struck the water; the water divided this way and that.&#x221D; The Jordan parting by Elijah&#x2019;s mantle echoes Moses parting the Sea of Reeds (Exod 14:21-22) and Joshua crossing the Jordan (Josh 3:14-17). Elijah stands in the sequence of the great exodus leaders; his mantle is his prophetic authority made physical.</p>",
        "10": "<p><em>hiqqāšîṯā liš'ōl</em> — &#x201C;You have asked a hard thing.&#x221D; <em>qāšāh</em> (hard, difficult) is used of the hardening of Pharaoh&#x2019;s heart and of impossible tasks. The condition Elijah sets — &#x201C;if you see me taken from you, it will be so for you&#x221D; — is not arbitrary but revelatory: only the one who can see the divine chariot has the spiritual capacity to inherit a double portion of prophetic spirit. The vision is both condition and confirmation.</p>",
        "11": "<p><em>wayhinnēh rekeb-ʾēš wᵉsûsê ʾēš wayyapriḏû bên šᵉnêhem wַיַּעַל ʾĒliyyāhû bassᵉʿārāh haššāmāyim</em> — &#x201C;behold, a chariot of fire and horses of fire separated the two of them, and Elijah went up to heaven in the whirlwind.&#x221D; The heavenly chariot (<em>rekeb ʾēš</em>) belongs to the same tradition as the divine chariot-throne in Ezekiel 1 and the heavenly armies of 2 Kings 6:17. Elijah is taken up (<em>yaʿal</em> — ascended) rather than dying — one of only two such departures in Hebrew Scripture (the other is Enoch, Gen 5:24).</p>",
        "12": "<p><em>ʾāḇî ʾāḇî rekeb Yiśrāʾēl ûpārāšāyw</em> — &#x201C;My father, my father! The chariot of Israel and its horsemen!&#x221D; Elisha&#x2019;s cry names Elijah as Israel&#x2019;s true military power — not chariots of iron or cavalry, but the prophet who prays down fire and rain. The same cry will be used at Elisha&#x2019;s deathbed (13:14), where Joash utters the same words over the dying prophet. It is a title of honor that identifies the prophet as more valuable to Israel than any army. Elisha then tears his own garments (<em>wayyeḥaṣṣēm</em>) — the mourning gesture of radical loss.</p>",
        "13": "<p><em>wayyārem ʾeṯ-ʾaddereṯ ʾĒliyyāhû ʾăšer nāpᵉlāh mēʿālāyw</em> — &#x201C;he took up the cloak of Elijah that had fallen from him.&#x221D; The mantle falling during the ascent is itself significant: Elijah does not consciously pass it to Elisha but it falls naturally — the succession is divinely ordained rather than humanly arranged. Picking it up is Elisha&#x2019;s act of claiming the inheritance. The mantle (<em>adderet</em>) is the same garment Elijah used to call Elisha at the plow (1 Kgs 19:19).</p>",
        "15": "<p>The sons of the prophets at Jericho see Elisha and prostrate before him: <em>wayyiqqadᵉdû lô ʾārṣāh</em> (they bowed to the ground before him). The gesture signals recognition of his succession to Elijah&#x2019;s authority. Their subsequent offer to search for Elijah — in case &#x201C;the spirit of YHWH has taken him up and thrown him on some mountain or valley&#x221D; — shows the community still processes the event literally rather than theologically. Elisha&#x2019;s refusal of the search is his first act of prophetic authority.</p>",
        "16": "<p>The sons of the prophets&#x2019; offer to send fifty strong men (<em>ḥămiššîm ʾanšê ḥāyil</em>) to search for Elijah reflects their expectation that divine transportation might deposit a living man somewhere. Their persistence despite Elisha&#x2019;s refusal — pressing him until he was embarrassed (<em>ad-bōš</em>, until shame) — illustrates the difficulty of the prophetic community accepting what they had witnessed. They send the search and return empty-handed.</p>",
        "17": "<p><em>wayyipṣᵉrû-ḇô ʿaḏ-bōš</em> — &#x201C;they pressed him until he was embarrassed/ashamed.&#x221D; <em>bōš</em> (shame/embarrassment) is used to describe Elisha&#x2019;s reluctant capitulation to the community&#x2019;s request. He says &#x201C;Send&#x201D; (<em>šilāḥû</em>). Their search confirms what Elisha already knew: Elijah is gone, not merely displaced. The narrative uses their fruitless search to establish the definitive nature of the translation.</p>",
        "18": "<p>The searchers return to Jericho after three days. Elisha&#x2019;s response — &#x201C;Did I not tell you, do not go?&#x221D; (<em>hălōʾ ʾāmarṯî ʾălêkem ʾal-tēlēḵû</em>) — is a gentle rebuke. The rhetorical question marks his prophetic knowledge as superior to their empirical search; he already knew what three days of searching would confirm.</p>",
        "19": "<p>The men of the city (Jericho) report bad water and infertile land (<em>hammāyim rāʿîm wᵉhāʾāreṣ mᵉšakkāleṯ</em> — &#x201C;the water is bad and the land is miscarrying/causing miscarriage&#x221D;). <em>šikkel</em> (cause miscarriage/bereave) describes land that causes premature death of plants and animals. Joshua&#x2019;s curse on Jericho (Josh 6:26) included no rebuilding; the bad water may be part of the curse&#x2019;s residual effect on the site.</p>",
        "20": "<p><em>qᵉḥû lî ṣallāḥaṯ ḥăḏāšāh wᵉśîmû šām melaḥ</em> — &#x201C;Bring me a new bowl and put salt in it.&#x221D; The new (unused, clean) bowl and salt are ritual objects for a healing/purification act. Salt is used in purification rites (Ezek 16:4; Lev 2:13); the combination of a new vessel and salt indicates a rite of consecration rather than a merely chemical treatment.</p>",
        "21": "<p><em>wayyēleḵ ʾel-môṣāʾ hammāyim wayyašleḵ-šām melaḥ wayyōʾmar kōh-ʾāmar YHWH rippîʾṯî lamāyim hāʾēlleh</em> — &#x201C;He went to the spring and threw salt into it and said: Thus says YHWH: I have healed these waters.&#x221D; Elisha performs the prophetic sign-act (throwing salt with a divine word), and the healing is attributed to YHWH&#x2019;s word rather than to the salt itself. The oracle introduced by the prophetic messenger formula demonstrates that this is authoritative divine action through prophetic mediation.</p>",
        "22": "<p><em>wayyērāpᵉʾû hammāyim ʿaḏ hayyôm hazzeh kidbar ʾĔlîšāʿ ʾăšer dibber</em> — &#x201C;The water was healed to this day, according to the word Elisha spoke.&#x221D; The fulfillment formula <em>kidbar ʾĔlîšāʿ</em> (according to Elisha&#x2019;s word) confirms the healing as prophetically accomplished. &#x201C;To this day&#x221D; is an archival note indicating that the tradition of the sweet water at Jericho was still told when Kings was composed.</p>",
        "23": "<p><em>wayyaʿal miššām bêṯ-ʾĒl wᵉhûʾ ʿōleh baddereḵ ûnᵉʿārîm qᵉṭannîm yāṣᵉʾû min-hāʿîr wayyiṯqalᵉsû-ḇô wayyōʾmᵉrû lô ʿălēh qērēaḥ ʿălēh qērēaḥ</em> — &#x201C;young boys came out of the city and mocked him, saying: Go up, baldhead! Go up, baldhead!&#x221D; <em>nᵉʿārîm qᵉṭannîm</em> (small/young boys) are juveniles rather than young men; <em>qērēaḥ</em> (baldhead) was apparently a term of mockery. Whether Elisha was actually bald or this was a general insult is debated; &#x201C;go up&#x221D; may mock the ascension of Elijah (&#x201C;you go up too!&#x221D;) or be a command to leave Bethel.</p>",
        "24": "<p><em>wayyipᵉn ʾaḥărāyw wayyirʾēm wayyᵉqallᵉlēm bᵉšēm YHWH wayyēṣᵉʾnāh šᵉtayim ḏubbîm min-hayyaʿar wattibbaqʿanāh mēhem arbaʿîm ûšᵉnê yᵉlāḏîm</em> — &#x201C;he turned around, looked at them, and called down a curse on them in the name of YHWH, and two female bears came out of the forest and mauled forty-two of the boys.&#x221D; <em>qilel</em> (curse) in YHWH&#x2019;s name is a prophetic act with divine authority. The narrative is disturbing to modern readers; it functions in the narrative as a defense of prophetic honor: mocking YHWH&#x2019;s prophet is mocking YHWH. The forty-two number is precise enough to be traditional; the two bears (<em>ḏubbîm</em>) from the forest complete the portrait of the land&#x2019;s danger when prophetic authority is rejected.</p>",
        "25": "<p>Elisha goes from Bethel to Mount Carmel — Elijah&#x2019;s mountain — and then returns to Samaria. The itinerary traces Elisha&#x2019;s establishment of his prophetic authority across the central hill country. Mount Carmel was associated with Elijah&#x2019;s great contest with the Baal prophets (1 Kgs 18); Elisha&#x2019;s visit there is his implicit claim to stand in that tradition.</p>"
    },
    "3": {
        "1": "<p>Joram son of Ahab begins to reign over Israel in the eighteenth year of Jehoshaphat of Judah — the synchronism is complex given the parallel chronologies. Joram will reign twelve years. He is the third king of the Omride dynasty after Omri, Ahab, and Ahaziah; his reign is the last of the dynasty before Jehu&#x2019;s purge (2 Kgs 9-10).</p>",
        "2": "<p><em>wayyaʿaś hāraʿ bᵉʿênê YHWH raq lōʾ ḵᵉʾāḇîw wᵉḵᵉʾimmô</em> — &#x201C;he did evil in YHWH&#x2019;s eyes, only not like his father and his mother.&#x221D; The qualified character formula is unusual — Joram is evil but distinctively less so than Ahab and Jezebel. Specifically: <em>wayyāser ʾeṯ-maṣṣeḇaṯ haBBaʿal ʾăšer ʿāśāh ʾāḇîw</em> (he removed the pillar of Baal his father had made). The removal of one cult object is credited to him; the Jeroboam calves he retains.</p>",
        "3": "<p><em>raq ḇᵉḥaṭṭōʾṯ Yarāḇᵉʿām ben-Nᵉḇāṭ ʾăšer heḥĕṭîʾ ʾeṯ-Yiśrāʾēl dāḇaq lōʾ-sār mimmennāh</em> — &#x201C;Nevertheless he clung to the sins of Jeroboam son of Nebat who caused Israel to sin; he did not turn from them.&#x221D; The Deuteronomic formula uses <em>dāḇaq</em> (cling/cleave) — the word of covenant loyalty (Ruth 1:14; Deut 10:20) — applied negatively: Joram cleaves to sin rather than to YHWH. The Jeroboam calves at Bethel and Dan represent the northern kingdom&#x2019;s structural unfaithfulness that persists across all its kings.</p>",
        "4": "<p><em>ûMêšāʿ melek-Môʾāḇ hāyāh nōqēḏ</em> — &#x201C;Mesha king of Moab was a sheep-farmer (<em>nōqēḏ</em>).&#x221D; The same term <em>nōqēḏ</em> describes Amos (Amos 1:1) — a keeper of herds, suggesting a man of substantial means rather than subsistence. Mesha&#x2019;s tribute (100,000 lambs and 100,000 rams with their wool) reflects Moab&#x2019;s pastoral economy. The Mesha Stele confirms his rule and his building programs financed by this agricultural wealth.</p>",
        "5": "<p><em>wayhî kᵉmôṯ ʾAḥāḇ wayyipšaʿ melek-Môʾāḇ bᵉmelek Yiśrāʾēl</em> — &#x201C;when Ahab died, the king of Moab rebelled.&#x221D; The verb <em>pāšaʿ</em> (rebel) repeats from 1:1, linking the two chapters: both Ahab&#x2019;s death and Ahaziah&#x2019;s death trigger rebellions. Political instability in Israel&#x2019;s ruling house creates opportunity for vassal revolt. The Mesha Stele confirms that Mesha&#x2019;s revolt occurred in this period: &#x201C;And Omri&#x2019;s son... he also occupied the land of Medeba... forty years.&#x221D;</p>",
        "6": "<p>Joram musters all Israel (<em>wayyipqōḏ ʾeṯ-kol-Yiśrāʾēl</em>) at Samaria — a full national military levy. The verb <em>pāqaḏ</em> (muster/count) is the census verb of military conscription. Joram&#x2019;s decision to respond militarily rather than simply accept Moab&#x2019;s independence reflects the importance of Moabite tribute to the Israelite economy.</p>",
        "7": "<p><em>wayyēlek wayyišlaḥ ʾel-Yᵉhôšāpāṭ melek-Yᵉhûḏāh lēmōr melek-Môʾāḇ pāšaʿ bî hatelēḵ ʾittî ʾel-Môʾāḇ lammilḥāmāh</em> — &#x201C;will you go with me against Moab to battle?&#x221D; The southern alliance between Israel and Judah is pragmatic despite the theological tension: Jehoshaphat has partnered with Ahab before (1 Kgs 22) and again here with Ahab&#x2019;s son. His response — <em>ʾeʿᵉleh kāmônî ḵāmôḵā kᵉʿammî kᵉʿammᵉḵā kᵉsûsay kᵉsûsêḵā</em> (&#x201C;I am as you are, my people as your people, my horses as your horses&#x221D;) — is the formula of complete military solidarity, verbatim from 1 Kings 22:4.</p>",
        "8": "<p><em>ḏereḵ midbar ʾĔḏôm</em> — &#x201C;by the way of the wilderness of Edom.&#x221D; The three-king coalition (Israel, Judah, Edom) takes a southern route through Edom&#x2019;s territory rather than the direct eastern approach. The inclusion of Edom (whose king is under Jehoshaphat&#x2019;s suzerainty) adds a third army and a southern pincer — tactical encirclement of Moab from an unexpected direction.</p>",
        "9": "<p>Seven days&#x2019; march around Edom produces a water crisis — <em>lōʾ-hāyāh māyim lammahăneh wᵉlabbᵉhēmāh ʾăšer bᵉraglêhem</em> (&#x201C;there was no water for the camp or for the animals with them&#x221D;). The logistical failure is a divine test: before the battle with Moab, the coalition must face the test of the wilderness. The word <em>maḥăneh</em> (camp/army) encompasses both military and livestock.</p>",
        "10": "<p><em>qārāʾ YHWH liš lōšeṯ hammᵉlāḵîm hāʾēlleh lāṯēṯ ʾôṯām bᵉyaḏ-Môʾāḇ</em> — &#x201C;YHWH has called these three kings together to hand them over to Moab!&#x221D; Joram&#x2019;s theological interpretation of the water shortage is pessimistic: he reads the military crisis as YHWH&#x2019;s rejection of the coalition. His lament demonstrates that even the Baal-tolerant northern king interprets military crisis in terms of YHWH&#x2019;s will — the Deuteronomic worldview is pervasive even where officially suppressed.</p>",
        "11": "<p>Jehoshaphat asks for a prophet of YHWH (<em>ʾên pōh nāḇîʾ lᵉYHWH</em>) — &#x201C;Is there no prophet of YHWH here?&#x221D; The royal officers identify Elisha by his relationship to Elijah: <em>ʾăšer yāṣaq-māyim ʿal-yᵉḏê ʾĒliyyāhû</em> — &#x201C;who poured water on the hands of Elijah.&#x221D; This is a servant&#x2019;s description — Elisha was Elijah&#x2019;s personal attendant before his succession. Jehoshaphat&#x2019;s immediate recognition — &#x201C;the word of YHWH is with him&#x221D; — reflects his knowledge of the prophetic tradition.</p>",
        "12": "<p><em>wayyēreḏ ʾēlāyw melek-Yiśrāʾēl wîhôšāpāṭ ûmelek ʾĔḏôm</em> — all three kings go down to Elisha. The reversal of the usual court protocol (prophets come to kings; here kings come to the prophet) signals Elisha&#x2019;s authority. &#x201C;Going down&#x201D; physically — perhaps Elisha was in a lower-lying area — also signals the condescension of royal power before prophetic authority.</p>",
        "13": "<p><em>mah-lî wālaḵ</em> — &#x201C;What do I have to do with you?&#x221D; Elisha&#x2019;s rebuke of Joram is a sharp rejection of casual prophetic consultation. The phrase is the standard formula for refusing an inappropriate demand (cf. John 2:4; Matt 8:29). His instruction — &#x201C;Go to the prophets of your father and the prophets of your mother&#x221D; — refers to the Baal and Asherah prophets of Ahab&#x2019;s court. Elisha serves the coalition only because Jehoshaphat of Judah is present.</p>",
        "14": "<p><em>ûlûlê pᵉnê Yᵉhôšāpāṭ melek-Yᵉhûḏāh ʾănî nōśēʾ ʾim-ʾabbîṭ ʾēlêḵā wᵉʾim-ʾerʾekā</em> — &#x201C;Were it not for the presence of Jehoshaphat king of Judah, I would not look at you or see you.&#x221D; Elisha&#x2019;s deference to Jehoshaphat is explicit — the Judahite king&#x2019;s fidelity to YHWH earns prophetic access for the coalition. The principle is that proximity to the faithful brings divine benefit even to the unfaithful.</p>",
        "16": "<p><em>kōh ʾāmar YHWH ʿāśōh hannaḥal hazzeh gēbîm gēbîm</em> — &#x201C;Thus says YHWH: Make this valley full of trenches.&#x221D; The oracle is instruction: the coalition must dig cisterns (<em>gēbîm</em> — pits, cisterns) without rain. This is a faith act — preparation for water that has not yet appeared. The oracle&#x2019;s structure (command + oracle of provision) parallels Elijah&#x2019;s jar that does not run out and the widow&#x2019;s oil: YHWH provides where preparation in faith has occurred.</p>",
        "17": "<p><em>kî kōh ʾāmar YHWH lōʾ-tirʾû rûaḥ wᵉlōʾ-tirʾû gešem ûhannaḥal hahûʾ yimmālēʾ māyim</em> — &#x201C;For thus says YHWH: You will not see wind or rain, yet that valley will be filled with water.&#x221D; The paradox — water without the natural means of water — is the sign of YHWH&#x2019;s sovereign action outside natural causation. The provision is designed to be unmistakably supernatural. Elisha adds: &#x201C;you will drink, you and your cattle and your animals.&#x221D;</p>",
        "18": "<p><em>wᵉnāqal zōʾṯ bᵉʿênê YHWH wᵉnātan ʾeṯ-Môʾāḇ bᵉyaḏᵉḵem</em> — &#x201C;This is a small thing in YHWH&#x2019;s eyes; he will also give Moab into your hand.&#x221D; The water provision is explicitly called a minor matter — the military victory is the main oracle. YHWH&#x2019;s power over Moab exceeds his power over natural water sources. The oracle lists a comprehensive Moabite defeat: every fortified city, every choice city, every good tree, every spring, every good field.</p>",
        "19": "<p><em>wᵉhikkîṯem kol-ʿîr miḇṣār wᵉḵol-ʿîr miḇḥār</em> — &#x201C;You will conquer every fortified city and every choice city.&#x221D; The conquest oracle extends to the economic infrastructure: felling every good tree (<em>kol-ʿēṣ ṭôḇ</em>), stopping every spring (<em>kol-maʿyan-māyim tisteṃmû</em>), ruining every good field (<em>kol-ḥelqaṯ haśśādeh taḥbilû ʾăḇānîm</em>). This scorched-earth warfare violates Deuteronomy 20:19-20&#x2019;s prohibition against cutting fruit trees — a theological tension the narrative does not resolve.</p>",
        "20": "<p><em>wayhî babbōqer kaʿălôṯ hamminhāh ûhinnēh māyim bāʾîm midderek ʾĔḏôm wayyimmālēʾ hāʾāreṣ ʾeṯ-hammāyim</em> — &#x201C;In the morning, at the time of the morning offering, water came from the direction of Edom and the land was filled with water.&#x221D; The timing — &#x201C;at the time of the morning offering&#x221D; — connects the water&#x2019;s arrival to the moment of temple sacrifice in Jerusalem: YHWH&#x2019;s provision coincides with the hour of Israel&#x2019;s proper worship. The oracle is fulfilled precisely as promised: no rain, no wind, but water from Edom&#x2019;s direction.</p>",
        "21": "<p>When all Moab heard that the coalition had come up to fight, <em>kol ʾăšer-ḥāgar ḥăgōrāh wāmaʿlāh wayyiṯyaṣṣᵉḇû ʿal-haggᵉḇûl</em> — &#x201C;everyone who could wear a belt and older stood at the border.&#x221D; The idiom &#x201C;girds a belt&#x221D; means capable of military service. Moab&#x2019;s total mobilization — every able-bodied man — reflects the seriousness of the threat from a three-king coalition.</p>",
        "22": "<p><em>wayyaškîmû babbōqer wᵉhaššemeš zārᵉḥāh ʿal-hammāyim wayyirʾû Môʾāḇ miNNEgeḏ ʾeṯ-hammāyim ʾăḏummîm kaddām</em> — &#x201C;the sun shone on the water and the Moabites saw the water as red as blood across from them.&#x221D; The red color of the water in morning sun is the basis of the Moabite misinterpretation: <em>dām zeh</em> — &#x201C;This is blood!&#x221D; The visual illusion leads them to assume the coalition has self-destructed, turning what YHWH provided as Israel&#x2019;s supply into a Moabite trap.</p>",
        "23": "<p><em>wayyōʾmᵉrû dām zeh ḥāreḇ nŒhéreḇû hammᵉlāḵîm wayyakkû ʾîš ʾeṯ-rēʿēhû</em> — &#x201C;They said: This is blood! The kings have surely destroyed each other — they have struck each other down!&#x221D; The Moabite commanders&#x2019; tactical error is divinely engineered: what they interpret as the aftermath of coalition self-destruction is actually the preparation of their opponents&#x2019; camp for battle. Their certainty (<em>ḥāreḇ ḥōreḇ</em> — the absolute infinitive of certainty) is their undoing.</p>",
        "24": "<p><em>wayyāḇōʾû ʾel-maḥănēh Yiśrāʾēl wayyāqumû Yiśrāʾēl wayyakkû ʾeṯ-Môʾāḇ wayyānûsû miPPᵉnêhem</em> — &#x201C;they came to the Israelite camp and Israel rose up and attacked Moab, and they fled before them.&#x221D; The battle reversal is total: the Moabites approached expecting to collect spoil from a defeated coalition and found a prepared army. They fled, and the coalition pursued into Moab with the scorched-earth program of v. 19.</p>",
        "25": "<p>The conquest of Moab is systematic: overthrow of cities, stones thrown on every good field (<em>kol-ḥelqaṯ haśśādeh yašlîḵû ʾîš ʾaḇnô ûmilʾûhā</em>), springs stopped, good trees felled — except Kir-hareseth (Kir-haraseth), which remained standing. The siege of Kir-hareseth eventually reached a crisis that triggers the chapter&#x2019;s most enigmatic episode.</p>",
        "26": "<p><em>wayyarʾ melek-Môʾāḇ kî-ḥāzaq mimmenû hammilḥāmāh wayyiqqaḥ ʾittô šibʿ-mēʾôṯ ʾîš šōlᵉpê ḥereḇ</em> — &#x201C;the king of Moab saw that the battle was too strong for him, and he took 700 swordsmen to break through to the king of Edom.&#x221D; The attempt at a breakout through the Edomite sector — perhaps Mesha judged Edom the weakest partner — failed. The seven hundred swordsmen were insufficient.</p>",
        "27": "<p><em>wayyiqqaḥ ʾeṯ-bᵉnô habbᵉḵôr ʾăšer-yimlōḵ taḥtāyw wayyaʿᵃlēhû ʿōlāh ʿal-haḥômāh</em> — &#x201C;he took his firstborn son who was to reign after him and offered him as a burnt offering on the wall.&#x221D; Mesha&#x2019;s sacrifice of his heir — the ultimate act of desperate devotion to his god Chemosh — produced a result the narrator describes with one of the most enigmatic phrases in Kings: <em>wayhî qeṣep gāḏôl ʿal-Yiśrāʾēl wayyisᵉʿû mēʿālāyw wayyāšuḇû lāʾāreṣ</em> — &#x201C;and there was great wrath (<em>qeṣep gāḏôl</em>) against Israel, and they withdrew from him and returned to their own land.&#x221D; Whether <em>qeṣep</em> is YHWH&#x2019;s wrath (perhaps against Israel&#x2019;s scorched-earth excess), the psychological force of the terrible act on the coalition, or Chemosh&#x2019;s wrath in Moabite theology, is debated without resolution. The narrative refuses to explain — the shock is the point.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', '2kings')
    merge_comm(existing, TWO_KINGS)
    save_comm('mkt-original', '2kings', existing)
    print('2 Kings original chapters 1–3 fill complete.')

if __name__ == '__main__':
    main()
